// src/AdminDashboard.js
import React from 'react';
import { Link, Outlet } from 'react-router-dom';
import './adminDashboard.css'; // Ensure this CSS file is present for styling

const AdminDashboard = () => {
  return (
    <div className="admin-dashboard container mt-4">
      <h1 className="text-center mb-4">Admin Dashboard</h1>
      <main className="dashboard-content">
        <div className="nav-container d-flex justify-content-around mb-4">
          <div className="nav-box p-3 shadow rounded">
            <Link to="add-officer" className="text-decoration-none">Add Officers</Link>
          </div>
          <div className="nav-box p-3 shadow rounded">
            <Link to="manage-officers" className="text-decoration-none">Manage Officers</Link>
          </div>
          <div className="nav-box p-3 shadow rounded">
            <Link to="add-project" className="text-decoration-none">Add Projects</Link>
          </div>
          <div className="nav-box p-3 shadow rounded">
            <Link to="manage-projects" className="text-decoration-none">Manage Projects</Link>
          </div>
        </div>
        <Outlet /> {/* This will render the child routes */}
      </main>
    </div>  
  );
};

export default AdminDashboard;
